/**
 * User Data Export API (LGPD/GDPR Compliance)
 *
 * POST /api/user/export — Request a new data export
 * GET  /api/user/export — Get export status / download
 *
 * Implements LGPD Art. 18, V and GDPR Art. 20 — data portability.
 * Uses the data-export engine from @/lib/compliance/data-export.
 */

import { NextRequest, NextResponse } from 'next/server';
import { logger } from '@lib/logger';
import { applyRateLimit } from '@/lib/rate-limit';
import { getServerAuth } from '@lib/auth/unified-session';
import {
  type UserProfileData,
  type ProjectData,
  type VideoData,
  type UserSettingsData,
  type StorageUsageData,
  type BillingData,
  type ExportRequest,
  buildUserDataExport,
  calculateExportSize,
  formatExportFilename,
  getExportExpiryDate,
  validateExportRequest,
  summarizeExport,
} from '@/lib/compliance/data-export';
import { randomUUID } from 'crypto';

// -------------------------------------------------------
// In-memory export store (production would use DB/Redis)
// -------------------------------------------------------

const exportStore = new Map<string, {
  request: ExportRequest;
  data: string | null; // JSON string
}>();

// Per-user last-export tracking
const lastExportByUser = new Map<string, string>();

// -------------------------------------------------------
// Data collection helpers
// -------------------------------------------------------

async function collectUserProfile(userId: string, userEmail: string): Promise<UserProfileData> {
  return {
    id: userId,
    email: userEmail,
    name: null,
    avatarUrl: null,
    createdAt: new Date().toISOString(),
    lastSignIn: new Date().toISOString(),
    provider: 'supabase',
    emailVerified: true,
  };
}

async function collectUserProjects(userId: string): Promise<ProjectData[]> {
  try {
    const { prisma } = await import('@lib/prisma');
    const projects = await prisma.projects.findMany({
      where: { userId },
      select: {
        id: true, name: true, description: true, status: true,
        createdAt: true, updatedAt: true,
      },
      take: 1000,
    });
    return projects.map(p => ({
      id: p.id,
      title: p.name,
      description: p.description,
      status: p.status ?? 'draft',
      slideCount: 0,
      duration: null,
      createdAt: (p.createdAt ?? new Date()).toISOString(),
      updatedAt: (p.updatedAt ?? new Date()).toISOString(),
      scenes: [],
    }));
  } catch {
    return [];
  }
}

async function collectUserVideos(userId: string): Promise<VideoData[]> {
  try {
    const { prisma } = await import('@lib/prisma');
    const jobs = await prisma.render_jobs.findMany({
      where: { userId },
      select: {
        id: true, projectId: true, status: true,
        createdAt: true, outputUrl: true,
      },
      take: 1000,
    });
    return jobs.map(j => ({
      id: j.id,
      projectId: j.projectId ?? '',
      title: `Video ${j.id.substring(0, 8)}`,
      status: j.status ?? 'unknown',
      duration: null,
      resolution: null,
      fileSize: null,
      format: null,
      createdAt: (j.createdAt ?? new Date()).toISOString(),
      downloadUrl: j.outputUrl ?? null,
    }));
  } catch {
    return [];
  }
}

function buildDefaultSettings(): UserSettingsData {
  return {
    language: 'pt-BR',
    theme: 'system',
    notifications: true,
    defaultVoice: null,
    defaultResolution: '1080p',
    onboardingCompleted: false,
  };
}

function buildStorageUsage(): StorageUsageData {
  return {
    totalBytes: 0,
    totalFiles: 0,
    breakdown: { videos: 0, images: 0, audio: 0, other: 0 },
  };
}

// -------------------------------------------------------
// POST — Request new export
// -------------------------------------------------------

export async function POST(request: NextRequest) {
  try {
    const rateLimitBlocked = await applyRateLimit(request, 'user-export-post', 5);
    if (rateLimitBlocked) return rateLimitBlocked;

    const session = await getServerAuth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Autenticação necessária' }, { status: 401 });
    }

    const userId = session.user.id;
    const userEmail = session.user.email || '';

    // Validate cooldown
    const lastExportAt = lastExportByUser.get(userId) || null;
    const validation = validateExportRequest(userId, lastExportAt);
    if (!validation.valid) {
      return NextResponse.json(
        { error: 'Export não permitido', reason: validation.reason },
        { status: 429 },
      );
    }

    const startTime = Date.now();
    const exportId = randomUUID();

    // Create pending export request
    const exportRequest: ExportRequest = {
      id: exportId,
      userId,
      status: 'processing',
      requestedAt: new Date().toISOString(),
      completedAt: null,
      downloadUrl: null,
      expiresAt: null,
      errorMessage: null,
      fileSize: null,
    };

    exportStore.set(exportId, { request: exportRequest, data: null });

    // Collect data
    const [profile, projects, videos] = await Promise.all([
      collectUserProfile(userId, userEmail),
      collectUserProjects(userId),
      collectUserVideos(userId),
    ]);

    const settings = buildDefaultSettings();
    const storage = buildStorageUsage();
    const billing: BillingData | null = null;

    const processingTimeMs = Date.now() - startTime;

    const exportData = buildUserDataExport({
      userId,
      exportId,
      profile,
      projects,
      videos,
      settings,
      activity: [{ type: 'data_export_requested', timestamp: new Date().toISOString(), details: null }],
      billing,
      storage,
      requestedAt: exportRequest.requestedAt,
      processingTimeMs,
    });

    const jsonData = JSON.stringify(exportData, null, 2);
    const fileSize = calculateExportSize(exportData);
    const completedAt = new Date().toISOString();
    const summary = summarizeExport(exportData);

    // Update export request
    const completed: ExportRequest = {
      ...exportRequest,
      status: 'completed',
      completedAt,
      downloadUrl: `/api/user/export?id=${exportId}&download=true`,
      expiresAt: getExportExpiryDate(completedAt),
      fileSize,
    };

    exportStore.set(exportId, { request: completed, data: jsonData });
    lastExportByUser.set(userId, completedAt);

    logger.info('User data export completed', {
      component: 'API: user/export',
      userId,
      exportId,
      fileSize,
      processingTimeMs,
    });

    return NextResponse.json({
      success: true,
      export: completed,
      summary,
    }, { status: 201 });
  } catch (error: unknown) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error('User data export failed', err, { component: 'API: user/export' });
    return NextResponse.json(
      { error: 'Falha ao exportar dados', message: err.message },
      { status: 500 },
    );
  }
}

// -------------------------------------------------------
// GET — Status or download
// -------------------------------------------------------

export async function GET(request: NextRequest) {
  try {
    const rateLimitBlocked = await applyRateLimit(request, 'user-export-get', 30);
    if (rateLimitBlocked) return rateLimitBlocked;

    const session = await getServerAuth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Autenticação necessária' }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const exportId = searchParams.get('id');
    const download = searchParams.get('download') === 'true';

    if (!exportId) {
      // List user's exports
      const userExports: ExportRequest[] = [];
      for (const entry of exportStore.values()) {
        if (entry.request.userId === session.user.id) {
          userExports.push(entry.request);
        }
      }
      return NextResponse.json({ exports: userExports });
    }

    const entry = exportStore.get(exportId);
    if (!entry || entry.request.userId !== session.user.id) {
      return NextResponse.json({ error: 'Export não encontrado' }, { status: 404 });
    }

    if (download && entry.data && entry.request.status === 'completed') {
      const filename = formatExportFilename(session.user.id, entry.request.completedAt || new Date().toISOString());
      return new NextResponse(entry.data, {
        status: 200,
        headers: {
          'Content-Type': 'application/json',
          'Content-Disposition': `attachment; filename="${filename}"`,
          'X-Export-Id': exportId,
        },
      });
    }

    return NextResponse.json({ export: entry.request });
  } catch (error: unknown) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error('User data export GET failed', err, { component: 'API: user/export' });
    return NextResponse.json(
      { error: 'Falha ao consultar exportação', message: err.message },
      { status: 500 },
    );
  }
}
